def mirror_tree(tree, root):
    stack = [root]
    while stack:
        node = stack.pop()
        if node in tree:
            left, right = tree[node]
            tree[node] = [right, left]
            stack.extend([left, right])

if __name__ == "__main__":
    tree = {1: [2, 3], 2: [4, 5]}
    mirror_tree(tree, 1)
    print(tree)
